import React, { useState, useEffect } from "react";
import { Card, CardContent, IconButton, Button, Tooltip, Dialog, DialogTitle, DialogContent } from "@mui/material";
import Select from "react-select";
import { customSelectStyles } from "../../Components/tablecolumn";
import { firstDayOfMonth, isEqualNumber, ISOString } from "../../Components/functions";
import { Close } from "@mui/icons-material";
import { fetchLink } from '../../Components/fetchComponent';
import FilterableTable from "../../Components/filterableTable2";

const FingerPrintAttendanceReport = () => {
    const storage = JSON.parse(localStorage.getItem('user'));
    const [attendanceData, setAttendanceData] = useState([]);


    const initialValue = {
        From: firstDayOfMonth(),
        To: ISOString(),
        EmpId: '',
        Name: '',
    }

    const [filter, setFilter] = useState(initialValue);
    const [dialog, setDialog] = useState(false);
    const [attendanceDetails, setAttendanceDetails] = useState([]);
    const [employees, setEmployees] = useState([]);
    const [isDropdownDisabled, setIsDropdownDisabled] = useState(false);



    useEffect(() => {
        const userTypeId = storage?.UserTypeId;
        const userId = storage?.UserId;
        const companyId = storage?.Company_id;

        fetchLink({
            address: `masters/users/employee/dropDown?Company_id=${companyId}`
        }).then(data => {
            if (data.success) {
                let filteredEmployees = [];


                if (isEqualNumber(userTypeId, 1) || isEqualNumber(userTypeId, 0)) {
                    filteredEmployees = data.data;
                    setFilter(prev => ({ ...prev, EmpId: '', Name: 'All Employees' }));
                    setIsDropdownDisabled(false);
                } else {

                    filteredEmployees = data.data.filter(employee => employee.UserId === userId);
                    setFilter(prev => ({ ...prev, EmpId: userId, Name: storage?.Name }));
                    setIsDropdownDisabled(true);
                }

                setEmployees(filteredEmployees);
            }
        }).catch(e => console.error("Error fetching employees:", e));
    }, [storage?.Company_id, storage?.UserTypeId, storage?.UserId]);


    const individualuserDetails = (From, To, EmpId) => {
        fetchLink({
            address: `userModule/employeActivity/trackActivitylogAttendance?FromDate=${From}&ToDate=${To}&UserId=${EmpId}`
        }).then(attendanceData => {
            if (attendanceData.success) {
                setAttendanceData(attendanceData.data);
            }
        }).catch(e => console.error("Error fetching attendance data:", e));
    }

    const allUsers = (From, To) => {
        const initialValue = {
            From: firstDayOfMonth(),
            To: ISOString(),
            EmpId: '',
            Name: '',
        }
        setFilter(initialValue)
        fetchLink({
            address: `userModule/employeActivity/trackActivitylogAttendance?FromDate=${From}&ToDate=${To}`
        }).then(attendanceData => {
            if (attendanceData.success) {
                setAttendanceData(attendanceData.data);
            }
        }).catch(e => console.error("Error fetching attendance data:", e));
    }


    useEffect(() => {
        const { From, To, EmpId } = filter;

        if (From && To && EmpId == null) {
            allUsers(From, To);
        }
    }, [filter.From, filter.To, filter.EmpId]);

    useEffect(() => {
        const { From, To, EmpId } = filter;

        if (From && To && EmpId != null) {
            individualuserDetails(From, To, EmpId);
        }
    }, [filter.EmpId, filter.From, filter.To]);

    const closeDialog = () => {
        setDialog(false);
        setAttendanceDetails([]);
    };

    const handleAttendanceClick = (attendanceDetailsStr) => {
        const attendanceArray = attendanceDetailsStr.split(",").map(item => {
            const [dateTime, status] = item.split(" (");
            return {
                LogDateTime: dateTime.trim(),
                AttendanceStatus: status.replace(')', '').trim()
            };
        });

        setAttendanceDetails(attendanceArray);
        setDialog(true);
    };

    const formatAttendanceDate = (logDateTime) => {
        if (!logDateTime) return '--';
        const [date] = logDateTime.split('T');
        return `${date} `;
    };

    return (
        <>
            <Card>
                <CardContent sx={{ minHeight: '50vh' }}>
                    <div className="ps-3 pb-2 pt-0 d-flex align-items-center justify-content-between border-bottom mb-3">
                        <h6 className="fa-18">Employee Attendance</h6>
                    </div>

                    <div className="px-2 row mb-4">
                        <div className="col-xl-2 col-lg-3 col-md-4 col-sm-6 p-2">
                            <label>Employee</label>
                            <Select
                                value={{ value: filter?.EmpId, label: filter?.Name }}
                                onChange={(e) => setFilter({ ...filter, EmpId: e.value, Name: e.label })}
                                options={[{ value: '', label: `All Employees` }, ...employees.map(obj => ({ value: obj?.UserId, label: obj?.Name }))]}
                                styles={customSelectStyles}
                                isSearchable={true}
                                placeholder="Employee Name"
                                isDisabled={isDropdownDisabled}  // Disable or enable based on userTypeId
                            />
                        </div>

                        <div className="col-xl-2 col-lg-3 col-md-4 col-sm-6 p-2">
                            <label>From</label>
                            <input
                                type="date"
                                className="cus-inpt"
                                value={filter?.From}
                                onChange={e => setFilter(prev => ({ ...prev, From: e.target.value }))}
                            />
                        </div>

                        <div className="col-xl-2 col-lg-3 col-md-4 col-sm-6 p-2">
                            <label>To</label>
                            <input
                                type="date"
                                className="cus-inpt"
                                value={filter?.To}
                                onChange={e => setFilter(prev => ({ ...prev, To: e.target.value }))}
                            />
                        </div>
                    </div>

                    <FilterableTable
                        dataArray={attendanceData}
                        columns={[
                            {
                                isCustomCell: true,
                                Cell: ({ row }) => row.username,
                                ColumnHeader: 'Employee',
                                isVisible: 1,
                            },
                            {
                                isCustomCell: true,
                                Cell: ({ row }) => formatAttendanceDate(row.LogDate || '--'),
                                ColumnHeader: 'Log Date',
                                isVisible: 1,
                            },
                            {
                                isCustomCell: true,
                                Cell: ({ row }) => (row.AttendanceStatus || '--'),
                                ColumnHeader: 'AttendanceStatus',
                                isVisible: 1,
                            },
                            {
                                isCustomCell: true,
                                Cell: ({ row }) => (
                                    <Button onClick={() => handleAttendanceClick(row.AttendanceDetails)}>
                                        View Details
                                    </Button>
                                ),
                                ColumnHeader: 'Action',
                                isVisible: 1,
                            }
                        ]}
                        EnableSerialNumber
                        CellSize="small"
                        disablePagination={true}
                    />
                </CardContent>
            </Card>

            <Dialog open={dialog} onClose={closeDialog} maxWidth="md" fullWidth>
                <DialogTitle>
                    Attendance Details
                    <IconButton onClick={closeDialog} style={{ position: 'absolute', right: 100, top: 10 }}>
                        <Close />
                    </IconButton>
                </DialogTitle>
                <DialogContent>
                    <FilterableTable
                        dataArray={attendanceDetails}
                        columns={[
                            {
                                isCustomCell: true,
                                Cell: ({ row }) => {
                                    const fullAttendanceDate = row.LogDateTime;
                                    let formattedAttendanceDate = '';
                                    if (fullAttendanceDate) {
                                        let dateObj = new Date(fullAttendanceDate);
                                        formattedAttendanceDate = dateObj.toDateString();
                                    }
                                    return (
                                        <div>
                                            <strong>{formattedAttendanceDate}</strong><br />
                                        </div>
                                    );
                                },
                                ColumnHeader: 'Log Date',
                                isVisible: 1,
                            },
                            {
                                isCustomCell: true,
                                Cell: ({ row }) => {
                                    const fullAttendanceDate = row.LogDateTime;
                                    let formattedAttendanceTime = '';
                                    if (fullAttendanceDate) {
                                        let dateObj = new Date(fullAttendanceDate);
                                        formattedAttendanceTime = dateObj.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', hour12: true });
                                    }
                                    return (
                                        <div>
                                            <strong>{formattedAttendanceTime}</strong><br />
                                        </div>
                                    );
                                },
                                ColumnHeader: 'Log Time',
                                isVisible: 1,
                            },

                            {
                                isCustomCell: true,
                                Cell: ({ row }) => `Punch ${row.AttendanceStatus}`,
                                ColumnHeader: 'Punch Details',
                                isVisible: 1,
                            }
                        ]}
                        EnableSerialNumber
                        CellSize="small"
                        disablePagination={true}
                    />
                </DialogContent>
            </Dialog>
        </>
    );
};

export default FingerPrintAttendanceReport;




